// Load & split the Learning Hub source list (one feed URL per line; # = comment).
// Emits one item per URL for the RSS reader. Missing file => no items (the
// aggregate step then produces a "reduced coverage" edition). Self-contained (fs).
const fs = require('fs');
const file = ($env.LEARNING_HUB_SOURCES_FILE || 'config/learning-hub-sources.txt');
const path = file.charAt(0) === '/' ? file : ('/' + file);
let lines = [];
try { lines = fs.readFileSync(path, 'utf8').split(/\r?\n/); } catch (e) { lines = []; }
const urls = lines.map(function (l) { return (l || '').trim(); })
  .filter(function (l) { return l && l.charAt(0) !== '#'; });
if (!urls.length) return [{ json: { url: '', _empty: true } }];
return urls.map(function (u) { return { json: { url: u } }; });

// Aggregate fetched RSS items into a compact news digest for the analyst.
// Robust to empty/failed feeds (reduced-coverage edition). No external deps.
const items = $input.all().map(function (i) { return i.json || {}; })
  .filter(function (a) { return a && (a.title || a.contentSnippet || a.content); });
function clean(s) { return String(s == null ? '' : s).replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim(); }
const seen = {};
const lines = [];
for (let k = 0; k < items.length && lines.length < 40; k++) {
  const a = items[k];
  const title = clean(a.title);
  if (!title || seen[title]) continue; seen[title] = 1;
  let sum = clean(a.contentSnippet || a.content || a.summary || '');
  if (sum.length > 280) sum = sum.slice(0, 280) + '…';
  const url = (a.link || a.guid || '').toString();
  lines.push('- ' + title + (sum ? (' — ' + sum) : '') + (url ? (' (' + url + ')') : ''));
}
const digest = lines.length
  ? lines.join('\n')
  : 'No fresh sources were available. Produce a timeless general security-awareness edition (phishing, passwords & MFA, social engineering, safe remote working, reporting incidents).';
return [{ json: { digest: digest, sourceCount: lines.length, date: new Date().toISOString().slice(0, 10) } }];

