const wm = '<svg class="wm" viewBox="0 0 24 24" fill="none" stroke="#9fe4d8" stroke-width="0.6"><path d="M12 3l7 3v5c0 4.5-3 7.6-7 9-4-1.4-7-4.5-7-9V6z"/><path d="M9 12l2 2 4-4"/></svg>';

// ---- cover ----
const toc = [];
if (f && f.headline) toc.push('Feature &middot; ' + esc(f.headline));
if (threats.length) toc.push('Emerging Threats');
if (aw.length) toc.push('The Human Firewall &mdash; ' + aw.length + ' habits');
if (quals.length) toc.push('Skills &amp; Qualifications');
if (gloss.length) toc.push('Jargon Buster');

let html = '<!doctype html><html><head><meta charset="utf-8"><style>' + CSS + '</style></head><body>';
html += '<section class="cover">'
 + (cover ? ('<div class="bg" style="background-image:url(' + cover + ')"></div>') : '<div class="bg ph"></div>')
 + wm + '<div class="grad"></div>'
 + '<div class="inner">'
 + '<div class="brandbar"><span>Security Awareness</span><span>Learning Hub</span></div>'
 + '<div class="masthead"><div class="kick">Staff Awareness Magazine</div>'
 + '<h1>' + esc(title) + '</h1>'
 + '<div class="edition">' + esc(weekOf || date) + ' Edition</div>'
 + (data.intro ? ('<div class="stand">' + esc(firstSentence(data.intro)) + '</div>') : '')
 + '</div>'
 + (toc.length ? ('<div class="toc"><div class="tl">Inside this issue</div><ul>' + toc.map(function(t){return '<li>' + t + '</li>';}).join('') + '</ul></div>') : '<div></div>')
 + '</div></section>';

// per-section accent [border/eyebrow colour, light tint background]
const AC = { ed:['#0E7C86','rgba(14,124,134,.08)'], feat:['#B8860B','rgba(201,162,75,.14)'], threat:['#B02525','rgba(176,37,37,.07)'], fire:['#0E7C86','rgba(14,124,134,.08)'], skill:['#0A1A2F','rgba(10,26,47,.06)'], gloss:['#46607a','rgba(70,96,122,.09)'] };
function header(eyebrow, t, key){ var a = AC[key] || AC.ed; return '<div class="band" style="border-left-color:' + a[0] + ';background:' + a[1] + '"><div class="eyebrow" style="color:' + a[0] + '">' + esc(eyebrow) + '</div><h2>' + esc(t) + '</h2></div>'; }
// lead paragraph (drop cap, full width) + remaining paragraphs in two columns.
function body2col(text){ var ps = String(text||'').split(/\n+/).map(function(s){return s.trim();}).filter(Boolean); if(!ps.length) return ''; var lead = '<p class="lead">' + esc(ps[0]) + '</p>'; var rest = ps.slice(1).map(function(p){return '<p>' + esc(p) + '</p>';}).join(''); return lead + (rest ? ('<div class="cols">' + rest + '</div>') : ''); }
// two-up card grid via a CSS table so cells in each row are equal height.
function cardTable(items, cellClass){ var rows = ''; for (var i = 0; i < items.length; i += 2){ var a = '<td class="' + cellClass + '">' + items[i] + '</td>'; var b = (i + 1 < items.length) ? ('<td class="' + cellClass + '">' + items[i + 1] + '</td>') : '<td class="empty"></td>'; rows += '<tr>' + a + b + '</tr>'; } return '<table class="cardtable">' + rows + '</table>'; }

// editorial
if (data.intro) {
  html += '<section class="sec">' + header('From the editor', 'Welcome to this edition', 'ed')
    + body2col(data.intro) + '</section>';
}
// feature
if (f && (f.headline || f.body)) {
  const pull = (A(f.takeaways)[0]) || f.deck || '';
  html += '<section class="sec feature">' + header('Feature', f.headline || 'In focus', 'feat')
    + imgph(f.image, 'feat-hero', 'Feature image')
    + (f.deck ? ('<div class="deck">' + esc(f.deck) + '</div>') : '')
    + (pull ? ('<div class="pull">&ldquo;' + esc(pull) + '&rdquo;</div>') : '')
    + body2col(f.body || '')
    + (A(f.takeaways).length ? ('<div class="take"><div class="th">Key takeaways</div><ul>' + A(f.takeaways).map(function(t){return '<li>' + esc(t) + '</li>';}).join('') + '</ul></div>') : '')
    + '</section>';
}
// threats
if (threats.length) {
  html += '<section class="sec">' + header('Threat radar', 'Emerging Threats', 'threat')
    + cardTable(threats.map(function(t){return imgph(t.image, 'thumb', '') + '<h3>' + esc(t.headline||'') + '</h3><p>' + esc(t.summary||'') + '</p>';}), 'cell tcell') + '</section>';
}
// human firewall
if (aw.length) {
  html += '<section class="sec">' + header('Practical habits', 'The Human Firewall', 'fire')
    + cardTable(aw.map(function(a,i){return '<span class="n">' + (i+1) + '</span><h3>' + esc(a.tip||'') + '</h3><p>' + esc(a.detail||'') + '</p>';}), 'cell tip') + '</section>';
}
// skills
if (quals.length) {
  html += '<section class="sec">' + header('Grow your skills', 'Skills & Qualifications', 'skill')
    + quals.map(function(q){return '<div class="qual"><h3>' + esc(q.name||'') + '</h3><div class="prov">' + esc(q.provider||'') + '</div><p>' + esc(q.summary||'') + '</p></div>';}).join('') + '</section>';
}
// glossary
if (gloss.length) {
  html += '<section class="sec">' + header('Plain English', 'Jargon Buster', 'gloss')
    + '<div class="gloss">' + gloss.map(function(g){return '<div class="gterm"><b>' + esc(g.term||'') + '</b> &mdash; ' + esc(g.definition||'') + '</div>';}).join('') + '</div></section>';
}
// closing sign-off (Jarvis AI avatar) — as per the other magazines
const AV = avatarUri();
html += '<div class="signoff">' + (AV ? ('<img src="' + AV + '"/>') : JARVIS_SVG) + '<div class="sg"><div class="nm">Jarvis</div><div class="rl">Your AI Awareness Editor</div></div></div>';
// references / further reading (links to the source articles)
const refs = [];
if (f && f.url) refs.push({ s: f.source || f.headline || 'Feature', u: f.url });
threats.forEach(function(t){ if (t && t.url) refs.push({ s: t.source || t.headline || 'Threat report', u: t.url }); });
quals.forEach(function(q){ if (q && q.url) refs.push({ s: q.provider || q.name || 'Course', u: q.url }); });
if (refs.length) {
  html += '<section class="sec refs">' + header('Sources', 'References & Further Reading', 'gloss')
    + '<ol>' + refs.map(function(r, i){ return '<li><span class="rn">' + (i+1) + '.</span> <b>' + esc(r.s) + '</b><br><a href="' + esc(r.u) + '">' + esc(r.u) + '</a></li>'; }).join('') + '</ol></section>';
}
html += '</body></html>';

return [{ json: { data: data, html: html, date: date, title: title, weekOf: weekOf, fileSafe: 'learning-hub-' + date } }];

// Wrap the rendered magazine HTML as an index.html binary for Gotenberg.
const meta = $('Render Magazine').first().json;
const buf = Buffer.from(meta.html || '<html></html>', 'utf8');
const bin = await this.helpers.prepareBinaryData(buf, 'index.html', 'text/html');
return [{ json: { date: meta.date, fileSafe: meta.fileSafe }, binary: { data: bin } }];

// Persist the magazine: PDF (from Gotenberg) + structured JSON archive.
// (No standalone .html artifact — the PDF is the deliverable.)
// Carries the parsed magazine data forward so the course can be grounded in it.
const fs = require('fs');
const meta = $('Render Magazine').first().json;
const dir = '/reports/learning-hub';
const archive = '/reports/archive/learning-hub';
const base = meta.fileSafe; // learning-hub-<date>
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
try { fs.mkdirSync(archive, { recursive: true }); } catch (e) {}
let pdfPath = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  if (buf && buf.length) { fs.writeFileSync(dir + '/' + base + '.pdf', buf); fs.writeFileSync(archive + '/' + base + '.pdf', buf); pdfPath = dir + '/' + base + '.pdf'; }
} catch (e) { pdfPath = ''; }
let jsonOk = false;
try { fs.writeFileSync(archive + '/' + base + '.json', JSON.stringify({ title: meta.title, weekOf: meta.weekOf, date: meta.date, data: meta.data }, null, 2)); jsonOk = true; } catch (e) {}
// Fail loudly (red node) rather than silently green if the output dir is not writable.
if (!jsonOk) throw new Error('Learning Hub: could not write to ' + dir + '. Make /reports writable by the n8n container, e.g. `chmod -R a+rwX reports` on the host.');
return [{ json: {
  ok: true,
  date: meta.date,
  title: meta.title,
  weekOf: meta.weekOf,
  data: meta.data,
  magazinePdf: pdfPath || (dir + '/' + base + '.pdf'),
  magazineHtml: '',
  fileSafe: base
} }];

// Build the e-learning "source" grounding text + course metadata from the magazine.
// Output is fed to the module's e-learning workflow (Execute Workflow) and reused
// by Register Publication. Keeps the course strictly about this edition's content.
const m = $json || {};
const data = m.data || {};
const date = m.date || new Date().toISOString().slice(0, 10);
const A = function (x) { return Array.isArray(x) ? x : []; };
function line(s) { return String(s == null ? '' : s).replace(/\s+/g, ' ').trim(); }
const parts = [];
parts.push('MAGAZINE TITLE: ' + (m.title || data.title || 'Security Awareness Digest'));
if (data.intro) parts.push('EDITORIAL: ' + line(data.intro));
const f = data.feature;
if (f && (f.headline || f.body)) {
  parts.push('FEATURE: ' + line(f.headline || '') + (f.deck ? (' — ' + line(f.deck)) : ''));
  if (f.body) parts.push(line(f.body));
  if (A(f.takeaways).length) parts.push('Key takeaways: ' + A(f.takeaways).map(line).join('; '));
}
if (A(data.threats).length) parts.push('EMERGING THREATS: ' + A(data.threats).map(function (t) { return line(t.headline) + ' — ' + line(t.summary); }).join(' | '));
if (A(data.awareness).length) parts.push('AWARENESS TIPS: ' + A(data.awareness).map(function (a) { return line(a.tip) + ': ' + line(a.detail); }).join(' | '));
if (A(data.quals).length) parts.push('SKILLS & QUALIFICATIONS: ' + A(data.quals).map(function (q) { return line(q.name) + ' (' + line(q.provider) + '): ' + line(q.summary); }).join(' | '));
if (A(data.glossary).length) parts.push('GLOSSARY: ' + A(data.glossary).map(function (g) { return line(g.term) + ' = ' + line(g.definition); }).join(' | '));
const source = parts.join('\n');
const title = (m.title || data.title || 'Security Awareness Digest') + ' — Awareness Course';
const pm = parseInt(($env.LEARNING_HUB_PASS_MARK || '80'), 10);
return [{ json: {
  source: source,
  title: title,
  passMark: isNaN(pm) ? 80 : pm,
  format: 'HTML',
  illustrate: (($env.ELEARNING_SECTION_IMAGES || 'true').toString().toLowerCase() !== 'false'),
  publicationId: 'learning-hub-' + date,
  courseId: 'course-learning-hub-' + date,
  releaseDate: date
} }];

// Upsert the publication record the dashboard reads. Links the magazine + the
// derived course, with the release date and 30-day completion window.
const fs = require('fs');
const dir = '/reports/learning-hub';
const file = dir + '/publications.json';
const src = ($('Build Course Source').first() || {}).json || {};
const mag = ($('Write Magazine').first() || {}).json || {};
const course = $json || {};
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
let store = { updated: '', publications: [] };
try { const cur = JSON.parse(fs.readFileSync(file, 'utf8')); if (cur && Array.isArray(cur.publications)) store = cur; } catch (e) {}
const entry = {
  id: src.publicationId || ('learning-hub-' + (src.releaseDate || '')),
  title: mag.title || src.title || 'Security Awareness Digest',
  kind: 'magazine',
  releaseDate: src.releaseDate || mag.date || new Date().toISOString().slice(0, 10),
  deadlineDays: 30,
  magazine: { pdf: mag.magazinePdf || '', html: mag.magazineHtml || '' },
  course: { id: src.courseId || '', html: course.html || course.file || '', title: src.title || '', passMark: src.passMark || 80 }
};
store.publications = store.publications.filter(function (p) { return p && p.id !== entry.id; });
store.publications.unshift(entry);
store.publications.sort(function (a, b) { return String(b.releaseDate).localeCompare(String(a.releaseDate)); });
store.updated = new Date().toISOString();
try { fs.writeFileSync(file, JSON.stringify(store, null, 2)); } catch (e) {}
return [{ json: { ok: true, publication: entry, total: store.publications.length, file: file } }];
